const normalizeFrontMatterRelationships = (frontMatter: TicketFrontMatter): TicketFrontMatter => {
  const ticketType = frontMatter.ticketType ?? "task";
  return {
    ...frontMatter,
    ticketType,
    parentEpicId: ticketType === "epic" ? null : frontMatter.parentEpicId ?? null,
    subticketIds: ticketType === "epic" ? uniqueTicketIds(frontMatter.subticketIds ?? []) : []
  };
};

const assertRelationshipShape = (frontMatter: TicketFrontMatter): void => {
  if (frontMatter.parentEpicId && frontMatter.parentEpicId === frontMatter.id) {
    throw new Error("A ticket cannot be linked as its own epic.");
  }
  if (frontMatter.ticketType === "epic" && frontMatter.parentEpicId) {
    throw new Error("Nested epics are not supported.");
  }
  if (frontMatter.ticketType === "task" && frontMatter.subticketIds.length > 0) {
    throw new Error("Only epic tickets can own subtickets.");
  }
  if (frontMatter.ticketType === "epic" && frontMatter.subticketIds.includes(frontMatter.id)) {
    throw new Error("An epic cannot include itself as a subticket.");
  }
};

const relativeMarkdownPath = (fromDirectory: string, toFile: string): string => {
  const relativePath = slashPath(pathRelative(fromDirectory, toFile));
  if (relativePath.startsWith(".") || relativePath.startsWith("/")) return relativePath;
  return `./${relativePath}`;
};

export const listTicketReferenceCandidates = async (projectPath: string): Promise<TicketReferenceCandidate[]> => {
  const resolvedProjectPath = resolveProjectPath(projectPath);
  const config = await readProjectConfig(resolvedProjectPath);
  const columnNames = new Map(config.columns.map((column) => [column.id, column.name]));
  const columnPositions = new Map(config.columns.map((column) => [column.id, column.position]));
  const { tickets } = await readTickets(resolvedProjectPath, config.columns);
  const ticketDirectory = ticketsPath(resolvedProjectPath);

  return [...tickets]
    .sort((a, b) => {
      const columnDelta = (columnPositions.get(a.status) ?? Number.MAX_SAFE_INTEGER) - (columnPositions.get(b.status) ?? Number.MAX_SAFE_INTEGER);
      if (columnDelta !== 0) return columnDelta;
      return a.position - b.position;
    })
    .map((ticket) => ({
      id: ticket.id,
      title: ticket.title,
      status: ticket.status,
      columnName: columnNames.get(ticket.status) ?? ticket.status,
      relativePath: slashPath(pathRelative(resolvedProjectPath, ticket.filePath)),
      linkPath: relativeMarkdownPath(ticketDirectory, ticket.filePath)
    }));
};

export const readTicket = async (projectPath: string, ticketId: string): Promise<TicketRecord> => {
  const resolvedProjectPath = resolveProjectPath(projectPath);
  const target = ticketPath(resolvedProjectPath, ticketId);
  try {
    return await readTicketFile(target);
  } catch (error) {
    if (isFileNotFoundError(error)) {
      throw new TicketNotFoundError(resolvedProjectPath, ticketId, target, error);
    }
    throw error;
  }
};

const assertEpicTicket = async (projectPath: string, epicId: string): Promise<TicketRecord> => {
  const epic = await readTicket(projectPath, epicId);
  if (epic.frontMatter.ticketType !== "epic") {
    throw new Error(`Ticket ${epicId} is not an epic.`);
  }
  return epic;
};

const addSubticketIdToEpic = async (projectPath: string, epicId: string, ticketId: string): Promise<TicketRecord> => {
  if (epicId === ticketId) {
    throw new Error("An epic cannot include itself as a subticket.");
  }
  const epic = await assertEpicTicket(projectPath, epicId);
  if (epic.frontMatter.subticketIds.includes(ticketId)) return epic;
  return writeTicket(projectPath, {
    ...epic,
    frontMatter: {
      ...epic.frontMatter,
      subticketIds: [...epic.frontMatter.subticketIds, ticketId]
    }
  });
};

const removeSubticketIdFromEpic = async (projectPath: string, epicId: string, ticketId: string): Promise<TicketRecord | null> => {
  try {
    const epic = await assertEpicTicket(projectPath, epicId);
    if (!epic.frontMatter.subticketIds.includes(ticketId)) return epic;
    return writeTicket(projectPath, {
      ...epic,
      frontMatter: {
        ...epic.frontMatter,
        subticketIds: epic.frontMatter.subticketIds.filter((id) => id !== ticketId)
      }
    });
  } catch (error) {
    if (isTicketNotFoundError(error)) return null;
    throw error;
  }
};

const validateParentEpic = async (projectPath: string, frontMatter: TicketFrontMatter): Promise<void> => {
  assertRelationshipShape(frontMatter);
  if (frontMatter.parentEpicId) {
    await assertEpicTicket(projectPath, frontMatter.parentEpicId);
  }
};

const stringifyTicket = (ticket: TicketRecord): string => {
  const body = ticket.markdown.trimStart();
  return matter.stringify(body.endsWith("\n") ? body : `${body}\n`, ticket.frontMatter);
};

export const writeTicket = async (projectPath: string, ticket: TicketRecord): Promise<TicketRecord> => {
  const target = ticketPath(projectPath, ticket.frontMatter.id);
  const frontMatter = normalizeFrontMatterRelationships(ticket.frontMatter);
  assertRelationshipShape(frontMatter);
  const next: TicketRecord = {
    ...ticket,
    filePath: target,
    frontMatter: {
      ...frontMatter,
      updatedAt: nowIso()
    }
  };
  await atomicWriteText(target, stringifyTicket(next));
  return next;
};

type TicketMarkdownDraft = TicketDraftSubticket & { research?: TicketDraft["research"] };

export const ticketMarkdownFromDraft = (draft: TicketMarkdownDraft): string => {
  const list = (items: string[]): string =>
    items.length > 0 ? items.map((item) => `- ${item.replace(/\s+/g, " ").trim()}`).join("\n") : "- None.";
  const researchMetadata = (): string => {
    if (
      !draft.research ||
      (draft.research.checkedUrls.length === 0 &&
        draft.research.inspectedFiles.length === 0 &&
        draft.research.limitations.length === 0)
    ) {
      return "- No research metadata recorded.";
    }
    const urls = draft.research.checkedUrls.map((source) => {
      const title = source.title ? ` (${source.title})` : "";
      const reason = source.reason ? ` - ${source.reason}` : "";
      return `- URL ${source.status}: ${source.url}${title}; characters read: ${source.charactersRead}${reason}`;
    });
    const files = draft.research.inspectedFiles.map((file) => {
      const symbols = file.symbols.length > 0 ? `; symbols: ${file.symbols.slice(0, 6).join(", ")}` : "";
      return `- File inspected: ${file.path} - ${file.reason}; characters read: ${file.charactersRead}${symbols}`;
    });
    const limitations = draft.research.limitations.map((limitation) => `- Limitation: ${limitation}`);
    return [...urls, ...files, ...limitations].join("\n");
  };
  return `# ${draft.title}

## Context

${draft.context || "No additional context provided."}

## Research Findings

${list(draft.researchFindings)}

## Requirements

${list(draft.requirements)}

## Implementation Plan

${list(draft.implementationPlan)}

## Acceptance Criteria

${list(draft.acceptanceCriteria)}

## Clarification Questions

${list(draft.clarificationQuestions)}

## Implementation Notes

${list(draft.implementationNotes)}

## Research Metadata

${researchMetadata()}

## Codex Handoff

No Codex run has been started.
`;
};

const createSingleTicket = async (projectPath: string, input: TicketCreateInput): Promise<TicketRecord> => {
  const config = await readProjectConfig(projectPath);
  const status = input.status ?? "todo";
  if (!config.columns.some((column) => column.id === status)) {
    throw new Error(`Unknown ticket status: ${status}`);
  }
  const ticketType: TicketType = input.ticketType ?? "task";
  if (ticketType === "epic" && input.parentEpicId) {
    throw new Error("Nested epics are not supported.");
  }
  const board = await readBoard(projectPath);
  const lastPosition = Math.max(0, ...board.tickets.filter((ticket) => ticket.status === status).map((ticket) => ticket.position));
  const createdAt = nowIso();
  const frontMatter: TicketFrontMatter = {
    schemaVersion: RELAY_SCHEMA_VERSION,
    id: newId("tkt"),
    title: input.title.trim(),
    ticketType,
    status,
    position: lastPosition + 1000,
    priority: input.priority,
    labels: input.labels.map((label) => label.trim()).filter(Boolean),
    parentEpicId: ticketType === "task" ? input.parentEpicId ?? null : null,
    subticketIds: [],
    createdAt,
    updatedAt: createdAt,
    codexThreadId: null,
    runStatus: "idle",
    lastRunId: null
  };
  await validateParentEpic(projectPath, frontMatter);
  const ticket: TicketRecord = {
    frontMatter,
    markdown: input.markdown,
    filePath: ticketPath(projectPath, frontMatter.id)
  };
  return writeTicket(projectPath, ticket);
};

const createSubticketRecord = async (
  projectPath: string,
  epicId: string,
  input: SubticketCreateInput
): Promise<TicketRecord> => {
  await assertEpicTicket(projectPath, epicId);
  const child = await createSingleTicket(projectPath, {
    ...input,
    ticketType: "task",
    parentEpicId: epicId,
    subtickets: []
  });
  await addSubticketIdToEpic(projectPath, epicId, child.frontMatter.id);
  return readTicket(projectPath, child.frontMatter.id);
};

export const createTicket = async (projectPath: string, input: TicketCreateInput): Promise<TicketRecord> => {
  const subtickets = input.subtickets ?? [];
  const ticketType: TicketType = input.ticketType ?? "task";
  if (ticketType !== "epic" && subtickets.length > 0) {
    throw new Error("Only epic tickets can be created with subtickets.");
  }
  const ticket = await createSingleTicket(projectPath, {
    ...input,
    ticketType,
    subtickets: [],
    subticketIds: []
  });

  if (ticket.frontMatter.parentEpicId) {
    await addSubticketIdToEpic(projectPath, ticket.frontMatter.parentEpicId, ticket.frontMatter.id);
  }

  for (const subticket of subtickets) {
    await createSubticketRecord(projectPath, ticket.frontMatter.id, subticket);
  }

  return readTicket(projectPath, ticket.frontMatter.id);
};

export const createSubticket = async ({ projectPath, epicId, ticket }: EpicSubticketCreateInput): Promise<TicketRecord> =>
  createSubticketRecord(projectPath, epicId, ticket);

export const linkSubticket = async (projectPath: string, epicId: string, ticketId: string): Promise<BoardSnapshot> => {
  if (epicId === ticketId) {
    throw new Error("An epic cannot include itself as a subticket.");
  }
  await assertEpicTicket(projectPath, epicId);
  const child = await readTicket(projectPath, ticketId);
  if (child.frontMatter.ticketType === "epic") {
    throw new Error("Nested epics are not supported.");
  }
  if (child.frontMatter.parentEpicId && child.frontMatter.parentEpicId !== epicId) {
    await removeSubticketIdFromEpic(projectPath, child.frontMatter.parentEpicId, ticketId);
  }
  await writeTicket(projectPath, {
    ...child,
    frontMatter: {
      ...child.frontMatter,
      parentEpicId: epicId,
      subticketIds: []
    }
  });
  await addSubticketIdToEpic(projectPath, epicId, ticketId);
  return readBoard(projectPath);
};

export const unlinkSubticket = async (projectPath: string, epicId: string, ticketId: string): Promise<BoardSnapshot> => {
  await assertEpicTicket(projectPath, epicId);
  const child = await readTicket(projectPath, ticketId);
  if (child.frontMatter.parentEpicId === epicId) {
    await writeTicket(projectPath, {
      ...child,
      frontMatter: {
        ...child.frontMatter,
        parentEpicId: null
      }
    });
  }
  await removeSubticketIdFromEpic(projectPath, epicId, ticketId);
  return readBoard(projectPath);
};

const calculatePosition = (tickets: TicketSummary[], targetStatus: string, beforeId?: string | null, afterId?: string | null): number => {
  const targetTickets = tickets
    .filter((ticket) => ticket.status === targetStatus && ticket.id !== beforeId && ticket.id !== afterId)
    .sort((a, b) => a.position - b.position);
  const before = beforeId ? tickets.find((ticket) => ticket.id === beforeId) : null;
  const after = afterId ? tickets.find((ticket) => ticket.id === afterId) : null;

  if (before && after) return (before.position + after.position) / 2;
  if (before) return before.position - 1000;
  if (after) return after.position + 1000;
  return (targetTickets.at(-1)?.position ?? 0) + 1000;
};

type StatusTransitionOptions = {
  actor: RelayActor;
  source: RelayEventSource;
  runId?: string | null;
  beforeTicketId?: string | null;
  afterTicketId?: string | null;
};

export const transitionTicketStatus = async (
  projectPath: string,
  ticketId: string,
  targetStatus: string,
  options: StatusTransitionOptions
): Promise<TicketRecord> => {
  const config = await readProjectConfig(projectPath);
  if (!config.columns.some((column) => column.id === targetStatus)) {
    throw new Error(`Unknown ticket status: ${targetStatus}`);
  }

  const board = await readBoard(projectPath);
  const record = await readTicket(projectPath, ticketId);
  const fromStatus = record.frontMatter.status;
  const position =
    fromStatus === targetStatus
      ? record.frontMatter.position
      : calculatePosition(board.tickets, targetStatus, options.beforeTicketId, options.afterTicketId);

  const updated = await writeTicket(projectPath, {
    ...record,
    frontMatter: {
      ...record.frontMatter,
      status: targetStatus,
      position
    }
  });

  if (fromStatus !== targetStatus) {
    await appendAuditEvent(projectPath, {
      actor: options.actor,
      source: options.source,
      eventType: "ticket.status_changed",
      ticketId,
      runId: options.runId ?? null,
      payload: {
        fromStatus,
        toStatus: targetStatus,
        position
      }
    });
  }

  return updated;
};

export const saveTicket = async (input: TicketSaveInput): Promise<TicketRecord> => {
  const config = await readProjectConfig(input.projectPath);
  const targetStatus = input.ticket.frontMatter.status;
  if (!config.columns.some((column) => column.id === targetStatus)) {
    throw new Error(`Unknown ticket status: ${targetStatus}`);
  }

  const existing = await readTicket(input.projectPath, input.ticket.frontMatter.id);
  const normalizedFrontMatter = normalizeFrontMatterRelationships(input.ticket.frontMatter);
  await validateParentEpic(input.projectPath, normalizedFrontMatter);
  const statusChanged = existing.frontMatter.status !== targetStatus;
  let position = input.ticket.frontMatter.position;
  if (statusChanged) {
    const board = await readBoard(input.projectPath);
    position = calculatePosition(board.tickets, targetStatus);
  }

  const updated = await writeTicket(input.projectPath, {
    ...input.ticket,
    frontMatter: {
      ...normalizedFrontMatter,
      position
    }
  });

  if (existing.frontMatter.parentEpicId && existing.frontMatter.parentEpicId !== updated.frontMatter.parentEpicId) {
    await removeSubticketIdFromEpic(input.projectPath, existing.frontMatter.parentEpicId, updated.frontMatter.id);
  }
  if (updated.frontMatter.parentEpicId && existing.frontMatter.parentEpicId !== updated.frontMatter.parentEpicId) {
    await addSubticketIdToEpic(input.projectPath, updated.frontMatter.parentEpicId, updated.frontMatter.id);
  }

  if (statusChanged) {
    await appendAuditEvent(input.projectPath, {
      actor: "user",
      source: "manual_ticket_edit",
      eventType: "ticket.status_changed",
      ticketId: updated.frontMatter.id,
      runId: updated.frontMatter.lastRunId,
      payload: {
        fromStatus: existing.frontMatter.status,
        toStatus: targetStatus,
        position
      }

}

const formatTimeout = (timeoutMs: number): string =>
  timeoutMs >= 1000 ? `${Math.round(timeoutMs / 1000)} seconds` : `${timeoutMs}ms`;

const isAbortLikeError = (error: unknown): boolean =>
  error instanceof Error && (error.name === "AbortError" || error.message.toLowerCase().includes("abort"));

const unrefTimeoutHandle = (handle: DraftTimeoutHandle): void => {
  if (typeof handle === "object" && handle && "unref" in handle && typeof handle.unref === "function") {
    handle.unref();
  }
};

const errorMessage = (error: unknown, fallback: string): string => (error instanceof Error ? error.message : fallback);

const normalizeWhitespace = (value: string): string => value.replace(/\s+/g, " ").trim();

const ticketDraftError = (
  code: TicketDraftErrorCode,
  requestId: string,
  durationMs: number,
  message: string,
  reason: string,
  options?: { timeoutMs?: number; recoverable?: boolean; cause?: unknown }
): TicketDraftServiceError =>
  new TicketDraftServiceError({
    code,
    message,
    recoverable: options?.recoverable ?? true,
    requestId,
    durationMs,
    reason,
    timeoutMs: options?.timeoutMs,
    cause: options?.cause
  });

const ticketDraftTimeoutError = (requestId: string, durationMs: number, timeoutMs: number, cause?: unknown): TicketDraftServiceError =>
  ticketDraftError(
    "timeout",
    requestId,
    durationMs,
    `Codex ticket drafting timed out after ${formatTimeout(timeoutMs)}. Your rough idea is still available; retry Codex when ready.`,
    "codex_generation_timeout",
    { timeoutMs, cause }
  );

const normalizeTicketDraftError = (
  error: unknown,
  context: {
    requestId: string;
    durationMs: number;
    timeoutMs: number;
    timedOut: boolean;
    signalAborted: boolean;
  }
): TicketDraftServiceError => {
  if (error instanceof TicketDraftServiceError) return error;
  if (context.timedOut) return ticketDraftTimeoutError(context.requestId, context.durationMs, context.timeoutMs, error);
  if (context.signalAborted || isAbortLikeError(error)) {
    return ticketDraftError(
      "cancelled",
      context.requestId,
      context.durationMs,
      "Codex ticket drafting was cancelled. Your rough idea is still available.",
      "codex_generation_cancelled",
      { timeoutMs: context.timeoutMs, cause: error }
    );
  }
  if (error instanceof ZodError || error instanceof SyntaxError || errorMessage(error, "").includes("valid JSON")) {
    return ticketDraftError(
      "invalid_response",
      context.requestId,
      context.durationMs,
      "Codex returned an invalid ticket draft. Your rough idea is still available; retry Codex when ready.",
      "invalid_codex_response",
      { timeoutMs: context.timeoutMs, cause: error }
    );
  }
  return ticketDraftError(
    "backend_failure",
    context.requestId,
    context.durationMs,
    errorMessage(error, "Ticket drafting failed."),
    "codex_backend_failure",
    { timeoutMs: context.timeoutMs, cause: error }
  );
};

export const ticketDraftErrorToPayload = (error: unknown): TicketDraftErrorPayload => {
  if (error instanceof TicketDraftServiceError) return error.toPayload();
  return {
    code: "backend_failure",
    message: errorMessage(error, "Ticket drafting failed."),
    recoverable: true,
    requestId: "unknown",
    durationMs: 0,
    reason: "unknown_ticket_draft_failure"
  };
};

const createTicketDraftPromise = async (
  { projectPath, idea, preferredTicketType }: CreateDraftInput,
  dependencies: TicketDraftDependencies = {}
): Promise<TicketDraft> => {
  const requestId = dependencies.createRequestId?.() ?? newId("tdr");
  const startedAt = dependencies.nowMs?.() ?? Date.now();
  const nowMs = dependencies.nowMs ?? Date.now;
  const durationMs = (): number => Math.max(0, nowMs() - startedAt);
  const draftTimeoutMs = dependencies.draftTimeoutMs ?? TICKET_DRAFT_TIMEOUT_MS;
  const setTimeoutFn = dependencies.setTimeoutFn ?? setTimeout;
  const clearTimeoutFn = dependencies.clearTimeoutFn ?? clearTimeout;
  let timeout: DraftTimeoutHandle | null = null;
  let timedOut = false;
  let abortController: AbortController | null = null;
  const logBase = { requestId, projectPath, ideaLength: idea.length, timeoutMs: draftTimeoutMs };

  await logInfo("codex:draft", "starting ticket draft", logBase);

  try {
    const status = await (dependencies.getStatus ?? getCodexStatus)();
    if (!status.cliAvailable) {
      await logWarn("codex:draft", "codex cli unavailable", { ...logBase, durationMs: durationMs(), status });
      throw ticketDraftError(
        "codex_unavailable",
        requestId,
        durationMs(),
        "Codex CLI was not found on PATH. Install or expose Codex before drafting tickets.",
        "codex_cli_unavailable",
        { timeoutMs: draftTimeoutMs }
      );
    }
    if (status.authenticated === false) {
      await logWarn("codex:draft", "codex auth unavailable", { ...logBase, durationMs: durationMs(), status });
      throw ticketDraftError(
        "codex_unauthenticated",
        requestId,
        durationMs(),
        "Codex is not authenticated. Run `codex login` in your terminal, then try drafting again.",
        "codex_auth_unavailable",
        { timeoutMs: draftTimeoutMs }
      );
    }

    const config = await readProjectConfig(projectPath);
    const research = await researchTicketDraft({ projectPath, idea, preferredTicketType }, dependencies);
    await logInfo("codex:draft", "ticket draft research completed", {
      ...logBase,
      durationMs: durationMs(),
      checkedUrlCount: research.metadata.checkedUrls.length,
      inspectedFileCount: research.metadata.inspectedFiles.length,
      limitationCount: research.metadata.limitations.length,
      limits: research.metadata.limits
    });
    const codex = dependencies.createCodexClient?.() ?? createCodex();
    const thread = codex.startThread(await threadOptionsForProject(projectPath));
    abortController = new AbortController();
    const ticketTypeGuidance =
      preferredTicketType === "epic"
        ? "The user selected Epic mode. Return ticketType \"epic\" and decompose the work into normal task subtickets."
        : "The user selected Task mode unless the idea explicitly asks for an epic. Return ticketType \"task\" with an empty subtickets array for ordinary work.";
    const prompt = `You are helping create a local software implementation ticket for Relay.

The user will provide a rough idea. Convert it into a clear, actionable ticket for a coding agent and human developer.

Use the bounded research context below to ground the ticket. Include concrete source references in researchFindings, such as file paths, function/component names, or URL titles. If research failed or was incomplete, state that limitation in researchFindings or implementationNotes.

Generate implementationPlan as specific engineering steps informed by the research context. Do not include large copied source blocks or long page excerpts.

Relay supports two ticket types: task and epic. ${ticketTypeGuidance}
For epic drafts, the parent epic should describe the overall outcome and subtickets should be independently implementable normal task tickets with their own requirements, implementationPlan, acceptanceCriteria, labels, and priority. Do not create nested epics. For task drafts, subtickets must be an empty array.

Return only data matching the requested schema. Do not implement the task.

Project path: ${projectPath}
Project name: ${config.name}
Current board columns: ${config.columns.map((column) => column.name).join(", ")}

Research context:
${renderResearchForPrompt(research)}

User idea:
${idea}`;

    const timeoutPromise = new Promise<never>((_resolve, reject) => {
      timeout = setTimeoutFn(() => {
        timedOut = true;
        abortController?.abort();
        reject(ticketDraftTimeoutError(requestId, durationMs(), draftTimeoutMs));
      }, draftTimeoutMs);
      if (dependencies.unrefTimeout !== false && timeout) unrefTimeoutHandle(timeout);
    });
    const runPromise = thread.run(prompt, { outputSchema: ticketDraftSchemaJson, signal: abortController.signal });
    void runPromise.then(
      () => {
        if (timedOut) {
          void logWarn("codex:draft", "late ticket draft completion ignored", {
            ...logBase,
            durationMs: durationMs(),
            reason: "late_completion_after_timeout"
          });
        }
      },
      (lateError) => {
        if (timedOut) {
          void logWarn("codex:draft", "late ticket draft failure ignored", {
            ...logBase,
            durationMs: durationMs(),
            reason: "late_failure_after_timeout",
            error: errorMessage(lateError, "unknown")
          });
        }
      }
    );

    const turn = await Promise.race([runPromise, timeoutPromise]);
    let parsed: TicketDraft;
    try {
      const parsedDraft = ticketDraftSchema.parse(parseJsonResponse(turn.finalResponse)) as TicketDraft;
      parsed = {
        ...parsedDraft,
        researchFindings:
          parsedDraft.researchFindings.length > 0 ? parsedDraft.researchFindings : fallbackResearchFindings(research.metadata),
        implementationPlan:
          parsedDraft.implementationPlan.length > 0 ? parsedDraft.implementationPlan : parsedDraft.implementationNotes,
        research: research.metadata
      };
    } catch (error) {
      throw ticketDraftError(
        "invalid_response",
        requestId,
        durationMs(),
        "Codex returned an invalid ticket draft. Your rough idea is still available; retry Codex when ready.",
        "invalid_codex_response",
        { timeoutMs: draftTimeoutMs, cause: error }
      );
    }
    await logInfo("codex:draft", "ticket draft completed", {
      ...logBase,
      durationMs: durationMs(),
      title: parsed.title,
      reason: "success"
    });
    return parsed;
  } catch (error) {
    const draftError = normalizeTicketDraftError(error, {
      requestId,
      durationMs: durationMs(),
      timeoutMs: draftTimeoutMs,
      timedOut,
      signalAborted: abortController?.signal.aborted ?? false
    });
    const failureMeta = { ...logBase, ...draftError.toPayload() };
    if (draftError.code === "timeout" || draftError.code === "cancelled") {
      await logWarn("codex:draft", "ticket draft did not complete", failureMeta);
    } else {
      await logError("codex:draft", "ticket draft failed", draftError, failureMeta);
    }
    throw draftError;
  } finally {
    if (timeout) clearTimeoutFn(timeout);
  }
};

const createTicketDraftEffect = (
  input: CreateDraftInput
): BackendEffect<TicketDraft, unknown, BackendServices | TicketDraftDependencyServices> =>
  Effect.gen(function*() {
    const dependencies = yield* TicketDraftDependencyService;
    return yield* fromPromise(() => createTicketDraftPromise(input, dependencies));
  });

export const createTicketDraft = (
  input: CreateDraftInput,
  dependencies: TicketDraftDependencies = {}
): Promise<TicketDraft> => runBackendEffect(Effect.provide(createTicketDraftEffect(input), ticketDraftDependencyLayer(dependencies)));

const emitRunEventForDependencies = (
  runEventSink: RendererRunEventSink | undefined,
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Promise<void> =>
  runEventSink
    ? emitRunEventToRendererSink(runEventSink, projectPath, ticketId, runId, threadId, event)
    : emitRunEvent(projectPath, ticketId, runId, threadId, event);

const finalTextFromItem = (item: ThreadItem): string | null => {
  if (item.type === "agent_message") return item.text;
  if (item.type === "error") return item.message;
  if (item.type === "reasoning") return item.text;
  return null;
};

const normalizeItemEvent = (
  event: Extract<ThreadEvent, { type: "item.started" | "item.updated" | "item.completed" }>,
  outputOffsets: Map<string, number>
): RelayCodexEvent[] => {
  const timestamp = nowIso();
  const item = event.item;

  if (item.type === "agent_message") {
    const text = item.text ?? "";
    return event.type === "item.completed"
      ? [{ type: "agent.message.completed", text, timestamp }]
      : [{ type: "agent.message.delta", text, timestamp }];
  }

  if (item.type === "reasoning" && item.text) {
    return [{ type: "agent.message.delta", text: item.text, timestamp }];
  }

  if (item.type === "command_execution") {
    const normalized: RelayCodexEvent[] = [];
    if (event.type === "item.started") {
      normalized.push({ type: "command.started", command: item.command, timestamp });
    }
    const offset = outputOffsets.get(item.id) ?? 0;
    const output = item.aggregated_output ?? "";
    if (output.length > offset) {
      normalized.push({ type: "command.output", stream: "stdout", text: output.slice(offset), timestamp });
      outputOffsets.set(item.id, output.length);
    }
    if (event.type === "item.completed") {
      normalized.push({
        type: "command.completed",
        status: item.status === "completed" ? "completed" : "failed",
        timestamp
      });
    }
    return normalized;
  }

  if (item.type === "file_change" && event.type === "item.completed") {
    return item.changes.map((change) => ({
      type: "file.change",
      path: change.path,
      summary: `${change.kind} ${change.path}`,
      timestamp
    }));
  }

  if (item.type === "error") {
    return [{ type: "run.failed", message: item.message, timestamp }];
  }

  if (item.type === "mcp_tool_call") {
    return [
      {
        type: "agent.message.delta",
        text: `${item.server}.${item.tool} ${item.status}`,
        timestamp
      }
    ];
  }

  if (item.type === "web_search") {
    return [{ type: "web.search", query: item.query, timestamp }];
  }

  ticket: SubticketCreateInput;
};

