import { Context, Effect, Layer } from "effect";
import type { AppRegistry } from "../../../shared/types";
import { getElectronPath } from "../../electron";
import { fromPromise, runBackendEffect } from "../runtime";
import { makeDirectoryEffect, pathDirname, pathJoin, pathResolve, readTextFileEffect, renamePathEffect, writeTextFileEffect } from "../io";
import { appRegistrySchema } from "../schemas";

const defaultRegistry = (): AppRegistry => ({
  schemaVersion: 1,
  projects: [],
  ui: {
    lastProjectPath: null,
    theme: "system"
  }
});

const registryPath = (): string => pathJoin(getElectronPath("userData"), "registry.json");

const readRegistryPromise = async (): Promise<AppRegistry> => {
  try {
    const raw = await runBackendEffect(readTextFileEffect(registryPath()));
    return appRegistrySchema.parse(JSON.parse(raw)) as AppRegistry;
  } catch {
    return defaultRegistry();
  }
};

const writeRegistryPromise = async (registry: AppRegistry): Promise<void> => {
  const target = registryPath();
  await runBackendEffect(makeDirectoryEffect(pathDirname(target)));
  const tmp = `${target}.tmp`;
  await runBackendEffect(writeTextFileEffect(tmp, `${JSON.stringify(registry, null, 2)}\n`));
  await runBackendEffect(renamePathEffect(tmp, target));
};

const upsertProjectPathPromise = async (projectPath: string): Promise<AppRegistry> => {
  const registry = await readRegistryPromise();
  const resolved = pathResolve(projectPath);
  const existing = registry.projects.find((project) => pathResolve(project.path) === resolved);
  const now = new Date().toISOString();

  if (existing) {
    existing.lastOpenedAt = now;
  } else {
    registry.projects.push({
      path: resolved,
      pinned: true,
      lastOpenedAt: now,
      sidebarPosition: (registry.projects.at(-1)?.sidebarPosition ?? 0) + 1000
    });
  }

  registry.ui.lastProjectPath = resolved;
  await writeRegistryPromise(registry);
  return registry;
};

const removeProjectPathPromise = async (projectPath: string): Promise<AppRegistry> => {
  const registry = await readRegistryPromise();
  const resolved = pathResolve(projectPath);
  registry.projects = registry.projects.filter((project) => pathResolve(project.path) !== resolved);
  if (registry.ui.lastProjectPath && pathResolve(registry.ui.lastProjectPath) === resolved) {
    registry.ui.lastProjectPath = registry.projects[0]?.path ?? null;
  }
  await writeRegistryPromise(registry);
  return registry;
};

export type RegistryStoreService = {
  readonly read: () => Effect.Effect<AppRegistry, unknown>;
  readonly write: (registry: AppRegistry) => Effect.Effect<void, unknown>;
  readonly upsertProjectPath: (projectPath: string) => Effect.Effect<AppRegistry, unknown>;
  readonly removeProjectPath: (projectPath: string) => Effect.Effect<AppRegistry, unknown>;
};

export const RegistryStore = Context.Service<RegistryStoreService>("relay/RegistryStore");

export const RegistryStoreLive = Layer.succeed(RegistryStore)({
  read: () => fromPromise(() => readRegistryPromise()),
  write: (registry) => fromPromise(() => writeRegistryPromise(registry)),
  upsertProjectPath: (projectPath) => fromPromise(() => upsertProjectPathPromise(projectPath)),
  removeProjectPath: (projectPath) => fromPromise(() => removeProjectPathPromise(projectPath))
});

export const readRegistry = (): Promise<AppRegistry> =>
  runBackendEffect(Effect.provide(RegistryStore.use((store) => store.read()), RegistryStoreLive));

export const writeRegistry = (registry: AppRegistry): Promise<void> =>
  runBackendEffect(Effect.provide(RegistryStore.use((store) => store.write(registry)), RegistryStoreLive));

export const upsertProjectPath = (projectPath: string): Promise<AppRegistry> =>
  runBackendEffect(Effect.provide(RegistryStore.use((store) => store.upsertProjectPath(projectPath)), RegistryStoreLive));

export const removeProjectPath = (projectPath: string): Promise<AppRegistry> =>
  runBackendEffect(Effect.provide(RegistryStore.use((store) => store.removeProjectPath(projectPath)), RegistryStoreLive));

import { Context, Effect, Layer } from "effect";
import type { RelayCodexEvent, RendererRunEvent } from "../../../shared/types";
import { RelayWindow } from "../../window/RelayWindow";
import { type BackendServices, fromPromise, runBackendEffect } from "../runtime";
import { appendTextFileEffect, isFileNotFoundError, makeDirectoryEffect, pathDirname, pathJoin, readTextFileEffect } from "../io";
import { runsPath } from "../storage";

export type RendererRunEventSink = {
  readonly emit: (event: RendererRunEvent) => void | Promise<void>;
};

export type RunEventSinkService = {
  readonly emit: (
    projectPath: string,
    ticketId: string,
    runId: string,
    threadId: string,
    event: RelayCodexEvent
  ) => Effect.Effect<void, unknown, BackendServices | Context.Service.Identifier<typeof RelayWindow>>;
};

export const RunEventSink = Context.Service<RunEventSinkService>("relay/RunEventSink");

export const rendererRunEventFromRelayEvent = (
  projectPath: string,
  ticketId: string,
  runId: string,
  event: RelayCodexEvent
): RendererRunEvent => ({
  ...event,
  projectPath,
  ticketId,
  runId
});

export const writeRunLogEffect = (
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Effect.Effect<void, unknown, BackendServices> =>
  Effect.gen(function*() {
    const filePath = pathJoin(runsPath(projectPath), ticketId, `${runId}.jsonl`);
    yield* makeDirectoryEffect(pathDirname(filePath));
    const { type, timestamp, ...payload } = event;
    yield* appendTextFileEffect(
      filePath,
      `${JSON.stringify({
        schemaVersion: 1,
        timestamp,
        ticketId,
        runId,
        threadId,
        type,
        payload
      })}\n`
    );
  });

export const writeRunLog = (
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Promise<void> => runBackendEffect(writeRunLogEffect(projectPath, ticketId, runId, threadId, event));

export const emitRunEventEffect = (
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Effect.Effect<void, unknown, BackendServices | Context.Service.Identifier<typeof RelayWindow>> =>
  Effect.gen(function*() {
    yield* writeRunLogEffect(projectPath, ticketId, runId, threadId, event);
    const relayWindow = yield* RelayWindow;
    yield* relayWindow.sendRunEvent(rendererRunEventFromRelayEvent(projectPath, ticketId, runId, event));
  });

export const RunEventSinkLive = Layer.succeed(RunEventSink)({
  emit: emitRunEventEffect
});

export const emitRunEvent = (
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Promise<void> => runBackendEffect(RunEventSink.use((sink) => sink.emit(projectPath, ticketId, runId, threadId, event)));

export const emitRunEventToRendererSink = (
  rendererSink: RendererRunEventSink,
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Promise<void> =>
  runBackendEffect(
    Effect.gen(function*() {
      yield* writeRunLogEffect(projectPath, ticketId, runId, threadId, event);
      yield* fromPromise(() => Promise.resolve(rendererSink.emit(rendererRunEventFromRelayEvent(projectPath, ticketId, runId, event))));
    })
  );

export const readRunEvents = async (projectPath: string, ticketId: string, runId: string): Promise<RendererRunEvent[]> => {
  const filePath = pathJoin(runsPath(projectPath), ticketId, `${runId}.jsonl`);
  let raw = "";
  try {
    raw = await runBackendEffect(readTextFileEffect(filePath));
  } catch (error) {
    if (isFileNotFoundError(error)) return [];
    throw error;
  }

  return raw
    .split("\n")
    .filter(Boolean)
    .map((line) => {
      const parsed = JSON.parse(line) as {
        timestamp: string;
        ticketId: string;
        runId: string;
        threadId: string;
        type: RelayCodexEvent["type"];
        payload: Record<string, unknown>;
      };
      return {
        ...parsed.payload,
        type: parsed.type,
        timestamp: parsed.timestamp,
        projectPath,
        ticketId: parsed.ticketId,
        runId: parsed.runId
      } as RendererRunEvent;
    });
};

        if (existingThreadId) {
          await emitRunEventForDependencies(runEventSink, projectPath, ticketId, runId, currentThreadId, {
            type: "run.started",
            runId,
            threadId: currentThreadId,
            timestamp: nowIso()
          });
          resolveOnce(currentThreadId);
        }

        for await (const event of streamed.events) {
          if (event.type === "thread.started") {
            currentThreadId = event.thread_id;
            await updateTicketRunState(projectPath, ticketId, {
              codexThreadId: currentThreadId,
              runStatus: "running",
              lastRunId: runId
            });
            await emitRunEventForDependencies(runEventSink, projectPath, ticketId, runId, currentThreadId, {
              type: "run.started",
              runId,
              threadId: currentThreadId,
              timestamp: nowIso()
            });
            resolveOnce(currentThreadId);
            continue;
          }

          if (event.type === "item.started" || event.type === "item.updated" || event.type === "item.completed") {
            const text = finalTextFromItem(event.item);
            if (event.item.type === "agent_message" && text) finalResponse = text;
            const normalized = normalizeItemEvent(event, outputOffsets);
            for (const relayEvent of normalized) {
              await emitRunEventForDependencies(runEventSink, projectPath, ticketId, runId, currentThreadId, relayEvent);
            }
            continue;
          }

          if (event.type === "turn.failed" || event.type === "error") {
            const message = event.type === "turn.failed" ? event.error.message : event.message;
            await updateTicketRunState(projectPath, ticketId, { runStatus: "failed" });
            await emitRunEventForDependencies(runEventSink, projectPath, ticketId, runId, currentThreadId, {
              type: "run.failed",
              message,
              timestamp: nowIso()
            });
            resolveOnce(currentThreadId);
            return;
          }

          if (event.type === "turn.completed") {
            const updated = await readTicket(projectPath, ticketId);
            const handoff = finalResponse || "Codex completed the run without a final text response.";
            const clarificationRequest = extractClarificationRequest(handoff);
            if (clarificationRequest.length > 0) {
              const questions = await createClarificationQuestions(projectPath, ticketId, clarificationRequest, {
                actor: "codex",
                source: "agent_execution",
                runId,
                codexThreadId: currentThreadId
              });
              const targetStatus = config.columns.some((column) => column.id === "needs_clarification")
                ? "needs_clarification"
                : updated.frontMatter.status;
              await updateTicketRunState(projectPath, ticketId, {
                runStatus: "blocked",
                lastRunId: runId,
                markdown: appendCodexHandoff(updated.markdown, handoff)
              });
              const blockedTransition = await transitionTicketStatus(projectPath, ticketId, targetStatus, {
                actor: "codex",
                source: "agent_execution",
                runId
              });
              if (updated.frontMatter.status !== blockedTransition.frontMatter.status) {
                await emitRunEventForDependencies(runEventSink, projectPath, ticketId, runId, currentThreadId, {
                  type: "ticket.status_changed",
                  fromStatus: updated.frontMatter.status,
                  toStatus: blockedTransition.frontMatter.status,
                  actor: "codex",
                  source: "agent_execution",
                  timestamp: nowIso()
                });
              }
              await emitRunEventForDependencies(runEventSink, projectPath, ticketId, runId, currentThreadId, {
                type: "clarification.requested",
                questions,
                timestamp: nowIso()
              });
              resolveOnce(currentThreadId);
              return;
            }

            const targetStatus = config.columns.some((column) => column.id === "completed") ? "completed" : updated.frontMatter.status;
            await updateTicketRunState(projectPath, ticketId, {
              runStatus: "completed",
              lastRunId: runId,
              markdown: appendCodexHandoff(updated.markdown, handoff)
            });
            const completedTransition = await transitionTicketStatus(projectPath, ticketId, targetStatus, {
              actor: "codex",
              source: "agent_execution",
              runId
            });
            if (updated.frontMatter.status !== completedTransition.frontMatter.status) {
              await emitRunEventForDependencies(runEventSink, projectPath, ticketId, runId, currentThreadId, {
                type: "ticket.status_changed",
                fromStatus: updated.frontMatter.status,
                toStatus: completedTransition.frontMatter.status,
                actor: "codex",
                source: "agent_execution",
                timestamp: nowIso()
              });
            }
            await emitRunEventForDependencies(runEventSink, projectPath, ticketId, runId, currentThreadId, {
              type: "run.completed",
              finalResponse: handoff,
              usage: event.usage,
              timestamp: nowIso()
            });
            resolveOnce(currentThreadId);
            return;
          }
        }
      } catch (error) {
        const aborted = abortController.signal.aborted;
        await logError("codex:run", aborted ? "run cancelled" : "run failed", error);
        await updateTicketRunState(projectPath, ticketId, { runStatus: aborted ? "cancelled" : "failed" });
        await emitRunEventForDependencies(runEventSink, projectPath, ticketId, runId, currentThreadId, {
          type: "run.failed",
          message: error instanceof Error ? error.message : "Codex run failed.",
          timestamp: nowIso()
        });
        resolveOnce(currentThreadId);
      } finally {
        activeRuns.delete(runId);
      }
    })();
  });

  return started;
};

